package powermetercontroller

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40000/event/userevent"
	"github.com/arminguenther/xeruspower-go/v40000/idl"
	"github.com/arminguenther/xeruspower-go/v40000/pdumodel/panel"
	"github.com/arminguenther/xeruspower-go/v40000/pdumodel/powermeter"
)

const (
	ERR_INVALID_PARAM    int32 = 1 // Invalid parameters
	ERR_METER_BOARD_BUSY int32 = 2 // A power meter with the given ID already exists
)

// Power Meter Controller (PMC) interface
type PowerMeterController interface {
	idl.Object

	// Scan for presence and configuration of a meter board.
	//
	//	@param powerMeterId  ID of meter board to be scanned
	//	@param result        Detected meter board properties
	//
	//	@return 0 if OK
	//	@return 1 if the meter board ID is out of range
	ScanMeterBoard(ctx context.Context, powerMeterId int32) (ret int32, result ScanResult, err error)

	// Retrieve the list of power meters and panels.
	//
	//	@return Power meter and panel instances, indexed by power meter ID
	GetPowerMeters(ctx context.Context) (map[int32]powermeter.PowerMeter, error)

	// Create a new standalone power meter (no panel).
	//
	//	@param powerMeter    Result: Newly created instance
	//	@param config        New power meter config
	//	@param settings      Power meter settings
	//
	//	@return 0 if OK
	//	@return 1 if any parameters are invalid
	//	@return 2 if a power meter with the given ID already exists
	CreatePowerMeter(ctx context.Context, config powermeter.Config, settings powermeter.Settings) (ret int32, powerMeter powermeter.PowerMeter, err error)

	// Create a new panel.
	//
	//	@param panel               Result: Newly created instance
	//	@param config              New power meter config
	//	@param powerMeterSettings  Power meter settings
	//	@param panelSettings       Panel settings
	//
	//	@return 0 if OK
	//	@return 1 if any parameters are invalid
	//	@return 2 if a power meter with the given ID already exists
	CreatePanel(ctx context.Context, config powermeter.Config, powerMeterSettings powermeter.Settings, panelSettings panel.Settings) (ret int32, panel panel.Panel, err error)

	// Delete a panel or power meter.
	//
	//	@param powerMeterId  Power meter ID
	//
	//	@return 0 if OK
	//	@return 1 if the power meter ID is invalid
	DeletePowerMeter(ctx context.Context, powerMeterId int32) (int32, error)
}

// Meter board scan result
type ScanResult struct {
	Present    bool  // Meter board was found
	MeterCount int32 // Number of meter channels
}

// Event: A power meter or panel was created
type PowerMeterCreatedEvent interface {
	userevent.UserEvent
	PowerMeter() powermeter.PowerMeter // New power meter instance
	Config() powermeter.Config         // New power meter config
	Settings() powermeter.Settings     // New power meter settings
	isPowerMeterCreatedEvent()
}

// Event: A power meter was deleted
type PowerMeterDeletedEvent interface {
	userevent.UserEvent
	Config() powermeter.Config     // Old power meter config
	Settings() powermeter.Settings // Old power meter settings
	isPowerMeterDeletedEvent()
}

// Event: A panel was created
type PanelCreatedEvent interface {
	PowerMeterCreatedEvent
	PanelSettings() panel.Settings // New panel settings
	isPanelCreatedEvent()
}

// Event:: A panel was deleted
type PanelDeletedEvent interface {
	PowerMeterDeletedEvent
	PanelSettings() panel.Settings // Old panel settings
	isPanelDeletedEvent()
}
